/* Basic Reset and Global Styles */
body,
html {
    margin: 0;
    padding: 0;
    font-family: 'EB Garamond', serif;
    color: #fff;
    background-color: #000;
}

/* Skip Navigation Link - Accessibility */
.skip-link {
    position: absolute;
    top: -40px;
    left: 0;
    background: #667eea;
    color: white;
    padding: 8px 16px;
    text-decoration: none;
    font-weight: bold;
    z-index: 10000;
    border-radius: 0 0 4px 0;
}

.skip-link:focus {
    top: 0;
    outline: 3px solid #fff;
    outline-offset: 2px;
}

/* Focus Styles for All Interactive Elements - WCAG AA Compliance */
button:focus,
a:focus,
.menu-toggle:focus,
.menu-item:focus,
.next-btn:focus,
.prev-btn:focus,
.start-btn:focus,
.dock-toggle-btn:focus,
.scroll-to-top-btn:focus {
    outline: 2px solid #667eea;
    outline-offset: 3px;
}

/* Enhanced focus for specific buttons */
.start-btn:focus,
.next-btn:focus,
.prev-btn:focus {
    outline: 3px solid #fff;
    outline-offset: 2px;
    box-shadow: 0 0 0 5px rgba(102, 126, 234, 0.3);
}

/* Focus for menu items */
.menu-item:focus {
    outline: 2px solid #8a2be2;
    outline-offset: 2px;
    background-color: rgba(138, 43, 226, 0.2);
}

/* Hamburger Menu Button */
.menu-toggle {
    position: fixed;
    top: 20px;
    left: 20px;
    z-index: 1000;
    width: 50px;
    height: 50px;
    background-color: rgba(138, 43, 226, 0.9);
    border: none;
    border-radius: 8px;
    cursor: pointer;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    gap: 6px;
    padding: 0;
    transition: all 0.3s ease;
    box-shadow: 0 4px 10px rgba(0, 0, 0, 0.5);
}

.menu-toggle:hover {
    background-color: rgba(138, 43, 226, 1);
    transform: scale(1.05);
}

.menu-toggle span {
    display: block;
    width: 25px;
    height: 3px;
    background-color: #fff;
    border-radius: 2px;
    transition: all 0.3s ease;
}

.menu-toggle.active span:nth-child(1) {
    transform: translateY(9px) rotate(45deg);
}

.menu-toggle.active span:nth-child(2) {
    opacity: 0;
}

.menu-toggle.active span:nth-child(3) {
    transform: translateY(-9px) rotate(-45deg);
}

/* Side Menu */
.side-menu {
    position: fixed;
    top: 0;
    left: -350px;
    width: 350px;
    height: 100vh;
    background: linear-gradient(to bottom, rgba(20, 20, 20, 0.98), rgba(0, 0, 0, 0.98));
    backdrop-filter: blur(10px);
    z-index: 999;
    transition: left 0.4s cubic-bezier(0.4, 0, 0.2, 1);
    overflow-y: auto;
    box-shadow: 2px 0 20px rgba(0, 0, 0, 0.8);
}

.side-menu.open {
    left: 0;
}

.menu-header {
    padding: 30px 20px 20px 90px;
    border-bottom: 2px solid rgba(138, 43, 226, 0.5);
}

.menu-header h3 {
    margin: 0;
    font-size: 1.5em;
    color: #fff;
}


.menu-list {
    list-style: none;
    padding: 20px 0;
    margin: 0;
}

.menu-list li {
    margin: 0;
}

.menu-item {
    display: block;
    padding: 15px 30px;
    color: #fff;
    text-decoration: none;
    font-size: 1.1em;
    transition: all 0.3s ease;
    border-left: 4px solid transparent;
}

.menu-item:hover {
    background-color: rgba(138, 43, 226, 0.2);
    border-left-color: #8a2be2;
    padding-left: 40px;
}

.menu-item:active {
    background-color: rgba(138, 43, 226, 0.4);
}

/* Menu Overlay */
.menu-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-color: rgba(0, 0, 0, 0.7);
    z-index: 998;
    opacity: 0;
    visibility: hidden;
    transition: all 0.4s ease;
}

.menu-overlay.active {
    opacity: 1;
    visibility: visible;
}

/* Hero Section */
.hero {
    height: 100vh;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    text-align: center;
    background: url('images/hero_bg.jpg') no-repeat center center/cover;
}

.hero h1 {
    font-size: 4em;
    text-shadow: 2px 2px 5px #000;
}

.hero h2 {
    font-size: 2em;
    text-shadow: 1px 1px 3px #000;
}

/* Story Sections */
.story-section {
    position: relative;
    height: 100vh;
    /* Each section takes up the full viewport height */
    overflow: hidden;
    /* Important for containing parallax children */
    z-index: 0;
}

.story-section::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: linear-gradient(
        to bottom,
        rgba(0, 0, 0, 0.7) 0%,
        rgba(0, 0, 0, 0.1) 10%,
        transparent 30%,
        transparent 70%,
        rgba(0, 0, 0, 0.1) 90%,
        rgba(0, 0, 0, 0.8) 100%
    );
    z-index: 1;
    pointer-events: none;
}

.background-parallax {
    position: absolute;
    top: -30vh;
    left: 0;
    width: 100%;
    height: 160vh;
    /* Make it taller to enable the parallax movement */
    background-size: cover;
    background-position: center center;
    z-index: -1;
    /* Place behind the content */
}

.background-parallax::after {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
