/* Scroll to Top Button */
.scroll-to-top-btn {
    position: fixed;
    bottom: 30px;
    right: 30px;
    width: 50px;
    height: 50px;
    background: linear-gradient(45deg, #667eea 0%, #764ba2 100%);
    color: white;
    border: none;
    border-radius: 50%;
    cursor: pointer;
    font-size: 20px;
    font-weight: bold;
    z-index: 1000;
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.3);
    transition: all 0.3s ease;
    opacity: 0;
    visibility: hidden;
    transform: translateY(20px);
}

.scroll-to-top-btn.visible {
    opacity: 1;
    visibility: visible;
    transform: translateY(0);
}

.scroll-to-top-btn:hover {
    background: linear-gradient(45deg, #764ba2 0%, #667eea 100%);
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(0, 0, 0, 0.4);
}

.scroll-to-top-btn:active {
    transform: translateY(0);
    box-shadow: 0 4px 10px rgba(0, 0, 0, 0.3);
}

.scroll-to-top-btn span {
    display: block;
    line-height: 1;
}

/* Responsive adjustments for scroll button */
@media (max-width: 768px) {
    .scroll-to-top-btn {
        bottom: 20px;
        right: 20px;
        width: 45px;
        height: 45px;
        font-size: 18px;
    }
}

/* Dock Toggle Button */
.dock-toggle-btn {
    position: absolute;
    top: 10px;
    right: 10px;
    width: 44px;
    height: 44px;
    background: rgba(255, 255, 255, 0.1);
    backdrop-filter: blur(10px);
    border: 2px solid rgba(255, 255, 255, 0.3);
    border-radius: 50%;
    color: #fff;
    font-size: 20px;
    cursor: pointer;
    z-index: 1000;
    transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.3);
    pointer-events: all;
}

.dock-toggle-btn:hover {
    background: rgba(255, 255, 255, 0.2);
    border-color: rgba(255, 255, 255, 0.5);
    transform: scale(1.1);
}

.dock-toggle-btn .dock-icon {
    transition: transform 0.3s ease;
    display: block;
}

/* Content Container Docked State - Collapse instead of translate */
.content-container {
    transition: all 0.6s cubic-bezier(0.4, 0, 0.2, 1);
    overflow: hidden;
}

.content-container.docked {
    width: 60px;
    max-width: 60px;
    min-height: 60px;
    height: auto;
    padding: 5px;
    left: auto;
    right: 20px;
    transform: translateY(-50%);
    background-color: rgba(102, 126, 234, 0.95);
    border: 2px solid rgba(118, 75, 162, 0.9);
    box-shadow: 0 6px 20px rgba(102, 126, 234, 0.4);
    cursor: pointer;
}

.content-container.docked:hover {
    transform: translateY(-50%) scale(1.08);
    background-color: rgba(118, 75, 162, 0.98);
    border-color: rgba(102, 126, 234, 1);
    box-shadow: 0 8px 30px rgba(102, 126, 234, 0.6),
                0 0 40px rgba(118, 75, 162, 0.4);
}

/* Hide content when docked, only show button */
.content-container.docked > *:not(.dock-toggle-btn) {
    opacity: 0;
    pointer-events: none;
    position: absolute;
    visibility: hidden;
}

/* When docked, center and style the button */
.content-container.docked .dock-toggle-btn {
    position: absolute;
    top: 50%;
    left: 50%;
    right: auto;
    transform: translate(-50%, -50%);
    background: transparent;
    border-color: rgba(255, 255, 255, 0.6);
    margin: 0;
    display: flex;
    align-items: center;
    justify-content: center;
}

.content-container.docked .dock-toggle-btn:hover {
    background: rgba(255, 255, 255, 0.1);
    transform: translate(-50%, -50%) scale(1.05);
}

.content-container.docked .dock-toggle-btn .dock-icon {
    display: block;
    transform: none;
    line-height: 1;
}

/* Undock hint when docked */
.content-container.docked .dock-toggle-btn::after {
    content: 'Expandir';
    position: absolute;
    right: calc(100% + 10px);
    top: 50%;
    transform: translateY(-50%);
    background: rgba(0, 0, 0, 0.9);
    color: white;
    padding: 6px 10px;
    border-radius: 6px;
    font-size: 11px;
    white-space: nowrap;
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.3s ease;
}

.content-container.docked .dock-toggle-btn:hover::after {
    opacity: 1;
}

/* Responsive adjustments for dock */
@media (max-width: 768px) {
    .dock-toggle-btn {
        width: 44px;
        height: 44px;
        font-size: 18px;
        top: 8px;
        right: 8px;
    }

    .content-container.docked {
        width: 50px;
        max-width: 50px;
        min-height: 50px;
        right: 10px;
    }
}

/* Add more specific styles and animations as needed */
/* Loading Screen */
.loading-screen {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100vh;
    background: radial-gradient(ellipse at center, #1a0033 0%, #000000 70%);
    z-index: 10000;
    display: flex;
    justify-content: center;
    align-items: center;
    transition: opacity 1s ease-out, visibility 1s ease-out;
}

.loading-screen.hidden {
    opacity: 0;
    visibility: hidden;
}

/* Fog Layers */
.fog-layer {
    position: absolute;
    width: 200%;
    height: 200%;
    background: radial-gradient(circle, rgba(138, 43, 226, 0.15) 0%, transparent 70%);
    opacity: 0;
}

.fog-1 {
    animation: fog-drift-1 8s ease-in-out infinite;
    animation-delay: 0s;
}

.fog-2 {
    animation: fog-drift-2 10s ease-in-out infinite;
    animation-delay: 2s;
}

.fog-3 {
    animation: fog-drift-3 12s ease-in-out infinite;
    animation-delay: 4s;
}

@keyframes fog-drift-1 {
    0%, 100% {
        transform: translate(-10%, -10%) scale(1);
        opacity: 0;
    }
    50% {
        transform: translate(10%, 10%) scale(1.5);
        opacity: 0.3;
    }
}

@keyframes fog-drift-2 {
    0%, 100% {
        transform: translate(10%, -10%) scale(1.2);
        opacity: 0;
    }
    50% {
        transform: translate(-10%, 10%) scale(1.8);
        opacity: 0.2;
    }
}

@keyframes fog-drift-3 {
    0%, 100% {
        transform: translate(-5%, 10%) scale(1.1);
        opacity: 0;
    }
    50% {
        transform: translate(5%, -10%) scale(1.6);
        opacity: 0.25;
    }
}

/* Loading Content */
.loading-content {
    position: relative;
    z-index: 10001;
    text-align: center;
    animation: mysterious-pulse 3s ease-in-out infinite;
}

.loading-logo {
    max-width: 300px;
    height: auto;
    filter: drop-shadow(0 0 30px rgba(138, 43, 226, 0.8)) drop-shadow(0 0 60px rgba(138, 43, 226, 0.4));
    animation: logo-glow 2s ease-in-out infinite alternate;
}

@keyframes logo-glow {
    0% {
        filter: drop-shadow(0 0 20px rgba(138, 43, 226, 0.6)) drop-shadow(0 0 40px rgba(138, 43, 226, 0.3));
        transform: scale(1);
    }
    100% {
        filter: drop-shadow(0 0 40px rgba(138, 43, 226, 1)) drop-shadow(0 0 80px rgba(138, 43, 226, 0.6));
        transform: scale(1.05);
    }
}

@keyframes mysterious-pulse {
    0%, 100% {
        opacity: 0.9;
    }
    50% {
        opacity: 1;
    }
}

.loading-text {
    margin-top: 30px;
    font-size: 1.5em;
    color: #fff;
    text-shadow: 0 0 10px rgba(138, 43, 226, 0.8), 0 0 20px rgba(138, 43, 226, 0.4);
    letter-spacing: 2px;
    opacity: 1;
    transition: opacity 0.4s ease-in-out, transform 0.4s ease-in-out;
    transform: translateY(0);
}

.loading-text.fade-out {
    opacity: 0;
    transform: translateY(-10px);
}

/* Loading Bar */
.loading-bar {
    width: 300px;
    height: 4px;
    background: rgba(138, 43, 226, 0.2);
    border-radius: 2px;
    margin: 20px auto 0;
    overflow: hidden;
    box-shadow: 0 0 10px rgba(138, 43, 226, 0.3);
}

.loading-progress {
    height: 100%;
    background: linear-gradient(90deg, 
        rgba(138, 43, 226, 0.8) 0%, 
        rgba(138, 43, 226, 1) 50%, 
        rgba(138, 43, 226, 0.8) 100%);
    box-shadow: 0 0 20px rgba(138, 43, 226, 0.8);
    animation: loading-progress 2s ease-in-out infinite;
    width: 0%;
}

@keyframes loading-progress {
    0% {
        width: 0%;
        transform: translateX(0);
    }
    50% {
        width: 70%;
    }
    100% {
        width: 100%;
    }
}

/* Reduced Motion Support - WCAG AA Compliance */
@media (prefers-reduced-motion: reduce) {
    /* Disable all animations and transitions */
    *,
    *::before,
    *::after {
        animation-duration: 0.01ms !important;
        animation-iteration-count: 1 !important;
        transition-duration: 0.01ms !important;
        scroll-behavior: auto !important;
    }

    /* Disable fog animations completely */
    .fog-layer {
        animation-name: none !important;
        animation-duration: 0s !important;
        opacity: 0 !important;
        display: none !important;
    }

    /* Disable loading screen animations */
    .loading-logo {
        animation: none !important;
    }

    .loading-text {
        transition: none !important;
    }

    /* Disable parallax effect */
    .background-parallax {
        transform: none !important;
        position: fixed !important;
    }

    /* Disable hover effects */
    .menu-toggle:hover,
    .menu-item:hover,
    .start-btn:hover,
    .next-btn:hover,
    .prev-btn:hover,
    .dock-toggle-btn:hover {
        transform: none !important;
    }

    /* Keep focus outlines for accessibility */
    *:focus {
        transition: none !important;
    }
}

